import React, { useState, useEffect } from 'react';
import { View, Button, Text, Alert } from 'react-native';
import * as AuthSession from 'expo-auth-session';
import * as WebBrowser from 'expo-web-browser';
import AsyncStorage from '@react-native-async-storage/async-storage';

WebBrowser.maybeCompleteAuthSession();

const App = () => {
  const [accessToken, setAccessToken] = useState(null);
  const [user, setUser] = useState(null);

  const discovery = {
    authorizationEndpoint: 'https://your-oauth-server.com/oauth/authorize',
    tokenEndpoint: 'https://your-oauth-server.com/oauth/token',
    revocationEndpoint: 'https://your-oauth-server.com/oauth/revoke',
  };

  const CLIENT_ID = 'your-public-client-id';
  const REDIRECT_URI = AuthSession.makeRedirectUri({ useProxy: true });

  const [request, response, promptAsync] = AuthSession.useAuthRequest(
    {
      clientId: CLIENT_ID,
      redirectUri: REDIRECT_URI,
      scopes: ['openid', 'profile', 'email'],
      usePKCE: true,
      responseType: AuthSession.ResponseType.Code,
    },
    discovery
  );

  useEffect(() => {
    if (response?.type === 'success') {
      const { code } = response.params;
      exchangeCodeForToken(code);
    }
  }, [response]);

  const exchangeCodeForToken = async (code) => {
    try {
      const tokenResponse = await AuthSession.exchangeCodeAsync(
        {
          clientId: CLIENT_ID,
          code,
          redirectUri: REDIRECT_URI,
          extraParams: {
            code_verifier: request.codeVerifier,
          },
        },
        discovery
      );

      await AsyncStorage.setItem('accessToken', tokenResponse.accessToken);
      await AsyncStorage.setItem('refreshToken', tokenResponse.refreshToken);
      setAccessToken(tokenResponse.accessToken);
      
      fetchUserData(tokenResponse.accessToken);
    } catch (error) {
      Alert.alert('Error', 'Failed to exchange code for token');
    }
  };

  const fetchUserData = async (token) => {
    try {
      const response = await fetch('https://your-oauth-server.com/api/user', {
        headers: { Authorization: `Bearer ${token}` },
      });
      const userData = await response.json();
      setUser(userData);
    } catch (error) {
      Alert.alert('Error', 'Failed to fetch user data');
    }
  };

  const handleLogin = () => {
    promptAsync({ useProxy: true });
  };

  const handleLogout = async () => {
    await AsyncStorage.removeItem('accessToken');
    await AsyncStorage.removeItem('refreshToken');
    setAccessToken(null);
    setUser(null);
  };

  return (
    <View style={{ flex: 1, justifyContent: 'center', padding: 20 }}>
      {!accessToken ? (
        <Button title="Login with OAuth" onPress={handleLogin} disabled={!request} />
      ) : (
        <View>
          <Text>Welcome, {user?.name || 'User'}!</Text>
          <Button title="Logout" onPress={handleLogout} />
        </View>
      )}
    </View>
  );
};

export default App;